import{_ as i,o as a,c as o,ag as l}from"./chunks/framework.BDReElpY.js";const h=JSON.parse('{"title":"vex-cli Reference","description":"","frontmatter":{},"headers":[],"relativePath":"references/vex-cli-reference.md","filePath":"references/vex-cli-reference.md"}'),r={name:"references/vex-cli-reference.md"};function n(t,e,c,s,d,p){return a(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="vex-cli-reference" tabindex="-1">vex-cli Reference <a class="header-anchor" href="#vex-cli-reference" aria-label="Permalink to &quot;vex-cli Reference&quot;">​</a></h1><p>This document describes <code>vex-cli</code> architecture, command pipeline, and extension points.</p><hr><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p><code>vex-cli</code> is the primary developer-facing command-line entry for:</p><ul><li>compile (<code>vex compile</code>)</li><li>run (<code>vex run</code>)</li><li>test (<code>vex test</code>)</li><li>toolchain integration with diagnostics, optimizer remarks, and package/native resolution</li></ul><hr><h2 id="command-surface" tabindex="-1">Command Surface <a class="header-anchor" href="#command-surface" aria-label="Permalink to &quot;Command Surface&quot;">​</a></h2><p>Main command modules are under:</p><ul><li><code>tools/vex-cli/src/commands/compile.rs</code></li><li><code>tools/vex-cli/src/commands/run.rs</code></li><li><code>tools/vex-cli/src/commands/test.rs</code></li><li><code>tools/vex-cli/src/commands/pipeline.rs</code></li></ul><h3 id="vex-compile" tabindex="-1"><code>vex compile</code> <a class="header-anchor" href="#vex-compile" aria-label="Permalink to &quot;`vex compile`&quot;">​</a></h3><p>Responsibilities:</p><ol><li>Resolve dependencies via <code>vex-pm</code></li><li>Build compiler pipeline via <code>CompilerDriver</code></li><li>Generate object file from LLVM module</li><li>Link executable with: <ul><li>runtime linker args (<code>vex_runtime::get_linker_args()</code>)</li><li>native package linker args (<code>vex_pm::get_native_linker_args_for_source(...)</code>)</li></ul></li><li>Emit optional artifacts (<code>.ll</code>, CFG, coverage)</li></ol><h3 id="vex-run" tabindex="-1"><code>vex run</code> <a class="header-anchor" href="#vex-run" aria-label="Permalink to &quot;`vex run`&quot;">​</a></h3><p>Responsibilities:</p><ol><li>Resolve deps + compile module</li><li>Decide JIT vs subprocess mode</li><li>If native external deps exist, switch to subprocess mode automatically</li><li>Link temporary executable with runtime + merged native linker args</li><li>Execute and report timings</li></ol><h3 id="vex-test" tabindex="-1"><code>vex test</code> <a class="header-anchor" href="#vex-test" aria-label="Permalink to &quot;`vex test`&quot;">​</a></h3><p>Responsibilities:</p><ol><li>Discover <code>*.test.vx</code> / <code>_test.vx</code></li><li>Generate test runner main when needed</li><li>Execute each test function with pass/fail markers</li><li>Handle compile errors and summarize results</li></ol><hr><h2 id="compiler-integration" tabindex="-1">Compiler Integration <a class="header-anchor" href="#compiler-integration" aria-label="Permalink to &quot;Compiler Integration&quot;">​</a></h2><p><code>vex-cli</code> delegates language pipeline to <code>CompilerDriver</code>:</p><ul><li>parsing</li><li>lowering</li><li>type/borrow checks</li><li>codegen</li></ul><p>This keeps command handlers thin while preserving shared compilation behavior.</p><hr><h2 id="linking-model" tabindex="-1">Linking Model <a class="header-anchor" href="#linking-model" aria-label="Permalink to &quot;Linking Model&quot;">​</a></h2><p>At link stage, <code>vex-cli</code> merges:</p><ol><li>runtime args (<code>vex_runtime</code>)</li><li>native args from package manifests (<code>vex-pm</code>)</li></ol><p>For optimized builds, ThinLTO is enabled where appropriate to reduce FFI overhead while preserving dynamic linking flexibility.</p><hr><h2 id="jit-behavior-and-safety" tabindex="-1">JIT Behavior and Safety <a class="header-anchor" href="#jit-behavior-and-safety" aria-label="Permalink to &quot;JIT Behavior and Safety&quot;">​</a></h2><p>JIT is used when possible for speed, but:</p><ul><li>if external native dependencies are detected, <code>run</code> switches to no-JIT subprocess</li><li>this avoids hardcoded symbol tables for arbitrary package-defined C APIs</li></ul><p>JIT path still registers core runtime + libc/libm/platform symbols needed by runtime.</p><hr><h2 id="diagnostics-and-ux" tabindex="-1">Diagnostics and UX <a class="header-anchor" href="#diagnostics-and-ux" aria-label="Permalink to &quot;Diagnostics and UX&quot;">​</a></h2><p><code>vex-cli</code> supports:</p><ul><li>JSON/non-JSON output modes</li><li>optimization remarks</li><li>sanitizer flags</li><li>coverage emission</li><li>lock-file aware dependency workflows</li></ul><hr><h2 id="key-extension-points" tabindex="-1">Key Extension Points <a class="header-anchor" href="#key-extension-points" aria-label="Permalink to &quot;Key Extension Points&quot;">​</a></h2><ul><li>Add new command: <code>tools/vex-cli/src/commands/</code></li><li>Extend CLI flags: command handler signatures + argument parser wiring</li><li>Add new link behavior: compile/run link stage argument builders</li><li>Add test behavior: <code>tools/vex-cli/src/commands/test.rs</code></li></ul><hr><h2 id="operational-notes" tabindex="-1">Operational Notes <a class="header-anchor" href="#operational-notes" aria-label="Permalink to &quot;Operational Notes&quot;">​</a></h2><ul><li>Native linking behavior is package-manifest driven (<code>vex.json/native</code>)</li><li><code>tools/vex-cli/build.rs</code> is intentionally no-op for package native logic (to avoid package-specific hardcoding)</li></ul><hr><h2 id="related-references" tabindex="-1">Related References <a class="header-anchor" href="#related-references" aria-label="Permalink to &quot;Related References&quot;">​</a></h2><ul><li><a href="./vex-pm-reference">vex-pm Reference</a></li><li><a href="./vex-pm-native-ffi">vex-pm Native FFI Pipeline</a></li></ul>',47)])])}const u=i(r,[["render",n]]);export{h as __pageData,u as default};
